import zipfile
import xml.etree.ElementTree as ET

# Parse financial_statements.xlsx
print('=== FINANCIAL_STATEMENTS.XLSX ===')
with zipfile.ZipFile('financial_statements.xlsx', 'r') as z:
    for sheet in ['xl/worksheets/sheet1.xml', 'xl/worksheets/sheet2.xml', 'xl/worksheets/sheet3.xml']:
        try:
            with z.open(sheet) as f:
                content = f.read().decode('utf-8')
                # Simple extraction - get row data
                ns = {'main': 'http://schemas.openxmlformats.org/spreadsheetml/2006/main'}
                root = ET.fromstring(content)
                print(f'\n--- Sheet: {sheet} ---')
                for row in root.findall('.//main:row', ns):
                    row_num = row.get('r', '')
                    cells = []
                    for cell in row.findall('main:c', ns):
                        ref = cell.get('r', '')
                        # Get value
                        v = cell.find('main:v', ns)
                        if v is not None:
                            cells.append(f'{ref}={v.text}')
                        else:
                            # Inline string
                            is = cell.find('main:is/main:t', ns)
                            if is is not None:
                                cells.append(f'{ref}={is.text}')
                    if cells:
                        print(f'Row {row_num}: {\" | \".join(cells)}')
        except Exception as e:
            print(f'Error reading {sheet}: {e}')
""}

